1	/**
2	 * POST /api/upload/signed/prepare
3	 *
4	 * Step 1 of 2 for the direct-to-storage upload flow. Works for ANY
5	 * supported file type — audio, PDF, DOCX, text, transcripts — not
6	 * just audio. The client POSTs metadata only, we:
7	 *
8	 *   1. validate auth + size against the `MAX_UPLOAD_BYTES` cap
9	 *      (default 500 MB);
10	 *   2. create an Upload row in `status='pending'` with storage
11	 *      placeholders;
12	 *   3. mint a one-shot signed-upload URL on Supabase Storage so the
13	 *      client can PUT the bytes directly, bypassing Vercel's 4.4 MB
14	 *      serverless body cap;
15	 *   4. return `{ uploadId, signedUrl, publicUrl, objectPath, isAudio }`.
16	 *
17	 * The client PUTs the file to `signedUrl` from the browser (getting
18	 * live progress via XHR), then calls
19	 * `/api/upload/signed/finalize/[id]`.
20	 *
21	 * This is the successor to the audio-only
22	 * `/api/upload/audio/prepare` endpoint. The old path is still
23	 * registered as a thin shim (see its route.ts) so Dialectic / other
24	 * external callers that hard-coded it don't break during rollout.
25	 *
26	 * If Supabase Storage isn't configured (SUPABASE_URL or
27	 * SUPABASE_SERVICE_ROLE_KEY missing), returns 501 so the client
28	 * falls back to the inline `/api/upload` path for small files.
29	 */
30	import { NextResponse } from "next/server";
31	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
32	import { db } from "@/lib/db";
33	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
34	import { sanitizeText, sanitizeAndCap } from "@/lib/sanitizeText";
35	import { pickAvailableSlug } from "@/lib/slugify";
36	import {
37	  createSignedAudioUploadUrl,
38	  ensureAudioBucketCapacity,
39	  getAudioBucket,
40	  isAudioStorageConfigured,
41	} from "@/lib/supabaseStorage";
42	
43	/**
44	 * Hard cap. Defaults to 500 MB so podcast episodes comfortably fit —
45	 * a 2-hour MP3 at 128 kbps is ~115 MB, a 2-hour WAV is ~1.2 GB
46	 * (trim it first). Override via env for heavier files, but note
47	 * that Supabase Storage also has its own per-file size limit
48	 * configured in the bucket settings — both need to permit the
49	 * upload for it to succeed. We read `MAX_UPLOAD_BYTES` first, then
50	 * fall back to the legacy `MAX_AUDIO_BYTES` name for anyone who
51	 * already set the old env var.
52	 */
53	const MAX_UPLOAD_BYTES = Number(
54	  process.env.MAX_UPLOAD_BYTES ||
55	    process.env.MAX_AUDIO_BYTES ||
56	    500 * 1024 * 1024,
57	);
58	
59	// Same allow-list the inline /api/upload enforces, plus .aac which
60	// modern podcast pipelines sometimes emit.
61	const ALLOWED_EXT = new Set([
62	  ".md",
63	  ".markdown",
64	  ".txt",
65	  ".vtt",
66	  ".jsonl",
67	  ".json",
68	  ".pdf",
69	  ".docx",
70	  ".mp3",
71	  ".m4a",
72	  ".wav",
73	  ".webm",
74	  ".ogg",
75	  ".aac",
76	]);
77	
78	const AUDIO_EXTS = new Set([
79	  ".mp3",
80	  ".m4a",
81	  ".wav",
82	  ".webm",
83	  ".ogg",
84	  ".aac",
85	]);
86	
87	function lowerExt(filename: string): string {
88	  const i = filename.lastIndexOf(".");
89	  return i >= 0 ? filename.slice(i).toLowerCase() : "";
90	}
91	
92	export async function POST(req: Request) {
93	  try {
94	    const founder = await getFounderFromAuth(req);
95	    if (!founder) {
96	      return NextResponse.json(
97	        { error: "Not authenticated" },
98	        { status: 401 },
99	      );
100	    }
101	    // Role gate: viewers don't get to mint signed URLs either. Without
102	    // this check the bucket would happily accept a viewer's PUT once
103	    // we'd handed them the signed URL, since the URL itself carries
104	    // the auth.
105	    if (!canWrite(founder.role)) {
106	      return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
107	    }
108	
109	    if (!isAudioStorageConfigured()) {
110	      return NextResponse.json(
111	        {
112	          error:
113	            "Direct upload needs Supabase Storage. Set SUPABASE_URL + " +
114	            "SUPABASE_SERVICE_ROLE_KEY on Vercel and redeploy, or fall " +
115	            "back to /api/upload for files under 3.5 MB. See " +
116	            "docs/Auto_Processing_Setup.md for the walkthrough.",
117	        },
118	        { status: 501 },
119	      );
120	    }
121	
122	    const body = (await req.json().catch(() => ({}))) as {
123	      filename?: string;
124	      mimeType?: string;
125	      size?: number;
126	      title?: string;
127	      description?: string;
128	      sourceType?: string;
129	      visibility?: string;
130	      publishAsPost?: boolean;
131	      blogExcerpt?: string;
132	      authorBio?: string;
133	      audioDurationSec?: number;
134	    };
135	
136	    const filename = (body.filename || "").trim();
137	    const size = Number(body.size || 0);
138	    const mimeType = (body.mimeType || "").toLowerCase();
139	
140	    if (!filename) {
141	      return NextResponse.json(
142	        { error: "filename is required" },
143	        { status: 400 },
144	      );
145	    }
146	    if (!size || !Number.isFinite(size) || size <= 0) {
147	      return NextResponse.json(
148	        { error: "size (bytes) is required and must be positive" },
149	        { status: 400 },
150	      );
151	    }
152	    if (size > MAX_UPLOAD_BYTES) {
153	      return NextResponse.json(
154	        {
155	          error:
156	            `File is ${(size / 1024 / 1024).toFixed(1)} MB — exceeds the ` +
157	            `${(MAX_UPLOAD_BYTES / 1024 / 1024).toFixed(0)} MB cap. Trim ` +
158	            `the file or raise MAX_UPLOAD_BYTES on Vercel. Note: ` +
159	            `Supabase also has a per-file "File size limit" in the ` +
160	            `bucket settings — raise that too.`,
161	        },
162	        { status: 413 },
163	      );
164	    }
165	
166	    // Supabase buckets enforce a per-file cap in addition to our
167	    // app-level MAX_UPLOAD_BYTES. When the bucket cap is lower than
168	    // the incoming file, Supabase rejects the direct PUT mid-flight
169	    // with a 413 "Payload too large" and the user sees a confusing
170	    // failure after a long upload wait.
171	    //
172	    // `ensureAudioBucketCapacity` fixes this by PATCH-ing the bucket
173	    // to raise its `file_size_limit` to at least the incoming file
174	    // size (defaulting to 500 MB so small-then-big upload sequences
175	    // don't trigger a raise every request). The service-role key has
176	    // admin privileges to do this. Earlier versions of this route
177	    // called `getAudioBucketFileSizeLimitBytes` and returned 413 if
178	    // the cap was lower — but if the bucket had no cap set at all
179	    // (common default), the read returned `null`, we skipped the
180	    // check, and the user hit the same Supabase-side 413 anyway.
181	    const ensure = await ensureAudioBucketCapacity(size);
182	    if (!ensure.ok) {
183	      const sizeMb = (size / 1024 / 1024).toFixed(1);
184	      let message: string;
185	      if (ensure.reason === "unconfigured") {
186	        message =
187	          "Supabase Storage is not configured on the server. Set " +
188	          "SUPABASE_URL + SUPABASE_SERVICE_ROLE_KEY on Vercel and " +
189	          "redeploy, then retry the upload.";
190	      } else if (ensure.reason === "plan_limit") {
191	        // The plan-level ceiling is the usual culprit here. On the
192	        // free tier it's 50 MB; on Pro it's 5 GB. The Storage API
193	        // refuses to let us raise the bucket's `file_size_limit`
194	        // above the plan ceiling even as a service-role request —
195	        // so if both the generous 500 MB target AND the exact file
196	        // size get rejected, the file genuinely exceeds what the
197	        // plan permits. We can't fix this in code; the user needs
198	        // to change one of: the file's size, the Supabase plan,
199	        // or (eventually) the storage backend itself.
200	        message =
201	          `Upload is ${sizeMb} MB, but your Supabase plan refuses ` +
202	          `to accept files that big. On the free tier the per-file ` +
203	          `ceiling is 50 MB; on Pro it rises to 5 GB. Three ways out:\n` +
204	          `  • Upgrade Supabase (Pro is $25/mo, ceiling becomes 5 GB): ` +
205	          `https://supabase.com/dashboard/project/_/settings/billing\n` +
206	          `  • Compress the audio below 50 MB — for an ~2 hour podcast, ` +
207	          `\`ffmpeg -i input.m4a -b:a 32k -ac 1 output.m4a\` usually ` +
208	          `lands around 30 MB.\n` +
209	          `  • Split into parts: ` +
210	          `\`ffmpeg -i input.m4a -f segment -segment_time 3600 -c copy part%d.m4a\` ` +
211	          `and upload each piece separately.`;
212	      } else {
213	        const detailSuffix = ensure.detail
214	          ? ` Supabase response: ${ensure.detail.slice(0, 200)}`
215	          : "";
216	        message =
217	          `Couldn't raise the Supabase bucket size limit to accept ` +
218	          `this ${sizeMb} MB file, and the failure isn't the usual ` +
219	          `plan-ceiling signal. Raise Storage → Bucket settings → ` +
220	          `File size limit manually, or check the SUPABASE_SERVICE_ROLE_KEY ` +
221	          `scope.${detailSuffix}`;
222	      }
223	      return NextResponse.json({ error: message }, { status: 413 });
224	    }
225	
226	    const ext = lowerExt(filename);
227	    const isAudio =
228	      mimeType.startsWith("audio/") || AUDIO_EXTS.has(ext);
229	
230	    if (!ALLOWED_EXT.has(ext) && !isAudio) {
231	      return NextResponse.json(
232	        {
233	          error:
234	            `Unsupported file type (${ext || mimeType || "unknown"}). ` +
235	            `Allowed: ${[...ALLOWED_EXT].join(", ")}.`,
236	        },
237	        { status: 400 },
238	      );
239	    }
240	
241	    // Visibility / publish parsing — same three-level contract as
242	    // /api/upload. See Upload.visibility in schema.prisma for the full
243	    // semantics of each level.
244	    const rawVisibility = (body.visibility || "org").toLowerCase();
245	    const visibility: "org" | "semi-private" | "private" =
246	      rawVisibility === "private"
247	        ? "private"
248	        : rawVisibility === "semi-private"
249	          ? "semi-private"
250	          : "org";
251	    const publishAsPost = Boolean(body.publishAsPost);
252	    if (visibility !== "org" && publishAsPost) {
253	      return NextResponse.json(
254	        {
255	          error:
256	            visibility === "private"
257	              ? "An upload can't be both private and published as a blog post. Choose one."
258	              : "An upload can't be both semi-private and published as a blog post. Choose one.",
259	        },
260	        { status: 400 },
261	      );
262	    }
263	
264	    // ── Sanitize + persist minimal metadata on the Upload row.
265	    const safeTitle =
266	      sanitizeText(
267	        (body.title && String(body.title).trim()) ||
268	          filename.replace(/\.[^/.]+$/, ""),
269	      ).slice(0, 500) || "Untitled upload";
270	    const safeDescription = sanitizeAndCap(body.description || "", 10_000);
271	    const safeOriginalName = sanitizeText(filename).slice(0, 500);
272	    const safeMime =
273	      sanitizeText(mimeType || "application/octet-stream").slice(0, 255) ||
274	      "application/octet-stream";
275	
276	    // Build a deterministic object path: <upload-id>/<filename-slug>.ext
277	    // We need the upload id BEFORE creating the row so the signed URL
278	    // can embed it. Prisma's `@default(cuid())` runs at insert time,
279	    // which is too late — so we mint a collision-resistant id from
280	    // Node's crypto primitives and pass it explicitly into create().
281	    const { randomBytes } = await import("crypto");
282	    const uploadId = "c" + randomBytes(14).toString("hex").slice(0, 24);
283	    const safeFilenamePart = filename.replace(/[^A-Za-z0-9._-]+/g, "_");
284	    const objectPath = `${uploadId}/${safeFilenamePart}`;
285	
286	    const handle = await createSignedAudioUploadUrl(objectPath);
287	    if (!handle) {
288	      return NextResponse.json(
289	        { error: "Could not mint a signed upload URL." },
290	        { status: 500 },
291	      );
292	    }
293	
294	    // Publish fields, only if requested and visibility allows.
295	    let publishFields: {
296	      publishedAt: Date;
297	      slug: string;
298	      blogExcerpt: string | null;
299	      authorBio: string | null;
300	    } | null = null;
301	    if (publishAsPost) {
302	      const slug = await pickAvailableSlug(safeTitle, async (candidate) => {
303	        const existing = await db.upload.findUnique({
304	          where: { slug: candidate },
305	          select: { id: true },
306	        });
307	        return existing !== null;
308	      });
309	      publishFields = {
310	        publishedAt: new Date(),
311	        slug,
312	        blogExcerpt: body.blogExcerpt
313	          ? sanitizeAndCap(body.blogExcerpt, 400)
314	          : null,
315	        authorBio: body.authorBio
316	          ? sanitizeAndCap(body.authorBio, 160)
317	          : null,
318	      };
319	    }
320	
321	    const duration =
322	      isAudio &&
323	      body.audioDurationSec &&
324	      Number.isFinite(body.audioDurationSec)
325	        ? Math.max(0, Math.floor(body.audioDurationSec))
326	        : null;
327	
328	    const upload = await db.upload.create({
329	      data: {
330	        id: uploadId,
331	        organizationId: founder.organizationId,
332	        founderId: founder.id,
333	        title: safeTitle,
334	        description: safeDescription,
335	        sourceType:
336	          sanitizeText(body.sourceType || (isAudio ? "audio" : "written")).slice(
337	            0,
338	            64,
339	          ),
340	        originalName: safeOriginalName,
341	        mimeType: safeMime,
342	        filePath: `storage:${objectPath}`,
343	        fileSize: size,
344	        status: "pending",
345	        processLog: sanitizeAndCap(
346	          `— Direct upload reserved (${(size / 1024 / 1024).toFixed(1)} MB) —\n` +
347	            `— Awaiting client PUT to Supabase Storage —\n`,
348	          8_000,
349	        ),
350	        visibility,
351	        // audioUrl is only set for audio rows, and only after the
352	        // PUT actually lands (in /finalize). Non-audio rows keep it
353	        // null.
354	        audioUrl: null,
355	        audioDurationSec: duration,
356	        ...(publishFields ?? {}),
357	      },
358	    });
359	
360	    await db.auditEvent
361	      .create({
362	        data: {
363	          organizationId: founder.organizationId,
364	          founderId: founder.id,
365	          uploadId: upload.id,
366	          action: "signed_upload_reserved",
367	          detail:
368	            `Reserved ${isAudio ? "audio" : "file"} slot for ${safeOriginalName} ` +
369	            `(${(size / 1024 / 1024).toFixed(1)} MB) at ${objectPath}`,
370	        },
371	      })
372	      .catch(() => {
373	        /* non-fatal */
374	      });
375	
376	    return NextResponse.json({
377	      uploadId: upload.id,
378	      signedUrl: handle.signedUrl,
379	      token: handle.token,
380	      publicUrl: handle.publicUrl,
381	      objectPath,
382	      isAudio,
383	      // The client includes these in its PUT so Supabase accepts it
384	      // cleanly regardless of the browser's default Content-Type
385	      // inference.
386	      headers: {
387	        "Content-Type": safeMime,
388	      },
389	    });
390	  } catch (err) {
391	    console.error("upload/signed/prepare error:", err);
392	    return NextResponse.json(
393	      {
394	        error: `Could not prepare upload: ${err instanceof Error ? err.message : "unknown error"}`,
395	      },
396	      { status: 500 },
397	    );
398	  }
399	}
