      textContent: result.textContent,
      note: result.note,
      hardFailed: result.hardFailed,
    };
  } catch (err) {
    return {
      textContent: null,
      note: `Storage fetch failed: ${err instanceof Error ? err.message : String(err)}`,
      hardFailed: true,
    };
